As an AI text model, I cannot directly render or display a 3D image. However, I can provide you with the **complete code** to generate a 3D house using **Three.js** (a popular JavaScript library for 3D graphics).

You can run this code immediately in your browser.

### Option 1: Run in CodePen (Easiest)
1. Go to [CodePen.io](https://codepen.io/pen/).
2. Paste the code below into the **HTML** section.
3. Click "Run".

### Option 2: Run Locally (HTML File)
1. Create a new file on your computer named `house.html`.
2. Paste the code below into that file.
3. Open the file with any web browser (Chrome, Firefox, Safari).

### The Code

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #instructions {
            position: absolute;
            top: 20px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="instructions">
        3D House Model<br>
        (Use Mouse to Rotate | Scroll to Zoom)
    </div>

    <!-- Import Three.js from a CDN -->
    <script type="module">
        import * as THREE from 'https://unpkg.com/three@0.160.0/build/three.module.js';
        import { OrbitControls } from 'https://unpkg.com/three@0.160.0/examples/jsm/controls/OrbitControls.js';

        // 1. SCENE SETUP
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 10, 50);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(5, 5, 8);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 2. CONTROLS (Mouse interaction)
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. LIGHTING
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. MATERIALS
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0xA52A2A, roughness: 0.8 });
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xF5F5DC, roughness: 0.5 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x333333 });
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.3 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 });

        // 5. BUILD THE HOUSE
        const houseGroup = new THREE.Group();

        // --- Ground ---
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const ground = new THREE.Mesh(groundGeo, grassMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // --- House Base ---
        const baseGeo = new THREE.BoxGeometry(4, 3, 4);
        const base = new THREE.Mesh(baseGeo, wallMaterial);
        base.position.y = 1.5; // Sit on top of ground
        base.castShadow = true;
        base.receiveShadow = true;
        houseGroup.add(base);

        // --- Roof ---
        const roofGeo = new THREE.ConeGeometry(3.5, 2, 4); // Pyramid shape
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 4; // Center of cone is at y=4, so tip is at y=5
        roof.rotation.y = Math.PI / 4; // Rotate to align with square base
        roof.castShadow = true;
        houseGroup.add(roof);

        // --- Door ---
        const doorGeo = new THREE.BoxGeometry(1, 2.5, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1.25, 2.1); // Front center
        houseGroup.add(door);

        // --- Windows (Simple Squares) ---
        const windowGeo = new THREE.BoxGeometry(1, 1, 0.2);

        // Front Window
        const win1 = new THREE.Mesh(windowGeo, windowMaterial);
        win1.position.set(0, 2, 2.1);
        houseGroup.add(win1);

        // Side Window
        const win2 = new THREE.Mesh(windowGeo, windowMaterial);
        win2.position.set(2.1, 2, 0);
        houseGroup.add(win2);

        // --- Chimney ---
        const chimneyGeo = new THREE.BoxGeometry(0.6, 1.5, 0.6);
        const chimney = new THREE.Mesh(chimneyGeo, wallMaterial);
        chimney.position.set(1.5, 4.5, 1.5);
        houseGroup.add(chimney);

        // Add House to Scene
        scene.add(houseGroup);

        // 6. ANIMATION LOOP
        function animate() {
            requestAnimationFrame(animate);
            controls.update(); // Required for damping
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### What this code does:
1.  **Sets up the Engine:** Uses Three.js to create a WebGL canvas.
2.  **Lighting:** Adds a sun (Directional Light) and ambient light so the house isn't pitch black.
3.  **Geometry:**
    *   **Base:** A cube for the walls.
    *   **Roof:** A cone rotated 45 degrees to create a pyramid roof.
    *   **Details:** Adds a door, windows, and a chimney using smaller boxes.
4.  **Shadows:** Enables shadow mapping so the house casts a shadow on the grass.
5.  **Interactivity:** Adds `OrbitControls`, allowing you to click and drag to rotate the view and scroll to zoom in/out.
